CREATE TABLE users(id uuid PRIMARY KEY,email text NOT NULL UNIQUE,password_hash text NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE projects(id uuid PRIMARY KEY,owner_id uuid NOT NULL REFERENCES users(id),version integer NOT NULL DEFAULT 1,schema jsonb NOT NULL,updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE project_snapshots(id bigserial PRIMARY KEY,project_id uuid NOT NULL REFERENCES projects(id),version integer NOT NULL,schema jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(project_id,version));
CREATE TABLE assets(id uuid PRIMARY KEY,owner_id uuid NOT NULL REFERENCES users(id),storage_key text NOT NULL,content_type text NOT NULL,size_bytes bigint NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE build_jobs(id uuid PRIMARY KEY,project_id uuid NOT NULL REFERENCES projects(id),owner_id uuid NOT NULL REFERENCES users(id),status text NOT NULL,error jsonb,qr_code_key text,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
